    elif 'gave' in line:
        # Pattern 2
        if M <= N:
            print(N - M)
        else:
            print('INVALID')
    elif 'gives' in line:
        # Pattern 3
        if M <= N:
            print(N - M)
        else:
            print('INVALID')
    else:
        print('INVALID')

